import React from "react";
import {AppBar, Typography,Toolbar, Button} from "@material-ui/core";

const NavBar = () =>{
    return(
        <AppBar position="static" square >
            <Toolbar>
                <Typography>

                        <Button color = "#000000" variant="contained">
                            Resume
                        </Button>
                </Typography>
            </Toolbar>
        </AppBar>
    )
}
export default NavBar;
